.pill{display:inline-flex;align-items:center;gap:6px;margin-top:14px;padding:5px 10px;border-radius:999px;font-size:11px;font-weight:800;letter-spacing:.03em}
.pill.positive{background:color-mix(in srgb,var(--_ok) 12%,var(--_bg));color:var(--_ok)}
.pill.mixed{background:color-mix(in srgb,var(--_partial) 13%,var(--_bg));color:var(--_partial)}
.pill.negative{background:color-mix(in srgb,var(--_no) 11%,var(--_bg));color:var(--_no)}
.verdict{display:flex;flex-direction:column;justify-content:center;padding:26px 28px}
.verdict-label{color:var(--_muted);font-size:10px;font-weight:850;letter-spacing:.12em;text-transform:uppercase}
.verdict-text{margin-top:7px;color:var(--_text);font-size:clamp(18px,3vw,24px);font-weight:780;letter-spacing:-.02em;line-height:1.3}
.verdict-copy{margin:10px 0 0;color:var(--_muted);font-size:13px;line-height:1.55}
.body{display:grid;grid-template-columns:minmax(0,1.2fr) minmax(240px,.8fr)}
.subscores{padding:23px 24px;border-right:1px solid var(--_line)}
.section-title{margin:0 0 16px;color:var(--_text);font-size:13px;font-weight:800;letter-spacing:.02em}
.metric+.metric{margin-top:18px}
.metric-head{display:flex;align-items:baseline;justify-content:space-between;gap:16px;margin-bottom:7px}
.metric-name{color:var(--_text);font-size:13px;font-weight:700}
.metric-score{color:var(--_muted);font-size:12px;font-weight:750;font-variant-numeric:tabular-nums}
.track{height:8px;overflow:hidden;border-radius:999px;background:var(--_group)}
.fill{height:100%;border-radius:inherit;background:var(--_accent)}
.fill.positive{background:var(--_ok)}.fill.mixed{background:var(--_partial)}.fill.negative{background:var(--_no)}
.metric-note{margin-top:6px;color:var(--_muted);font-size:11px;line-height:1.4}
.lists{display:grid;gap:20px;padding:23px 24px;align-content:start}
.list-title{display:flex;align-items:center;gap:7px;margin:0 0 10px;color:var(--_text);font-size:12px;font-weight:800}
.list-title .icon,.point .icon{display:inline-flex;flex:0 0 auto;align-items:center;justify-content:center;border-radius:999px;font-weight:850}
.list-title .icon{width:22px;height:22px}
.list-title.pro .icon,.point.pro .icon{background:color-mix(in srgb,var(--_ok) 12%,var(--_bg));color:var(--_ok)}
.list-title.con .icon,.point.con .icon{background:color-mix(in srgb,var(--_no) 11%,var(--_bg));color:var(--_no)}
.point{display:flex;align-items:flex-start;gap:9px;color:var(--_text);font-size:12px;line-height:1.45}
.point+.point{margin-top:9px}
.point .icon{width:19px;height:19px;margin-top:0;font-size:11px}
.empty{padding:42px 24px;color:var(--_muted);font-size:14px;text-align:center}
@media (max-width:680px){.summary,.body{grid-template-columns:1fr}.overall{border-right:0;border-bottom:1px solid var(--_line)}.subscores{border-right:0;border-bottom:1px solid var(--_line)}}
@media (max-width:520px){.heading{padding:18px}.overall,.verdict,.subscores,.lists{padding:20px 18px}}

@media (prefers-color-scheme:dark){:host{--_bg:var(--ov-bg,#0f172a);--_raised:var(--ov-bg,#111827);--_text:var(--ov-text,#e5e7eb);--_muted:var(--ov-muted,#9ca3af);--_line:var(--ov-line,#293548);--_accent:var(--ov-accent,#818cf8);--_ok:var(--ov-ok,#34d399);--_no:var(--ov-no,#fb7185);--_partial:var(--ov-partial,#fbbf24);--_soft:#111827;--_group:#182235;--_accent-soft:#1b2145;--_hover:#172033}.frame{box-shadow:0 14px 34px rgba(0,0,0,.28)}}
`;
const sheet = new CSSStyleSheet(); sheet.replaceSync(CSS); root.adoptedStyleSheets=[sheet];

const make = (tag,className,text) => { const node=document.createElement(tag); if(className) node.className=className; if(text!==undefined) node.textContent=text; return node; };
const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Review scorecard';
const max=Number(data.maxScore)>0?Number(data.maxScore):100;
const raw=Number(data.score); const score=Number.isFinite(raw)?Math.max(0,Math.min(max,raw)):0; const percent=max?score/max*100:0;
const requestedTone=['positive','mixed','negative'].includes(data.verdictTone)?data.verdictTone:null;
const tone=requestedTone||(percent>=80?'positive':percent>=60?'mixed':'negative');
const toneLabel=tone==='positive'?'✓ Strong':tone==='mixed'?'Partial':'✗ Needs work';
const subscores=Array.isArray(data.subscores)?data.subscores:[];
const pros=Array.isArray(data.pros)?data.pros:[]; const cons=Array.isArray(data.cons)?data.cons:[];
const frame=make('section','frame'); frame.setAttribute('aria-label',title);
const heading=make('header','heading'); heading.appendChild(make('div','eyebrow','Review scorecard')); heading.appendChild(make('h2','',title));
if(data.subject) heading.appendChild(make('div','subject',String(data.subject))); frame.appendChild(heading);
const summary=make('div','summary');
const overall=make('div','overall'); const scoreLine=make('div','score-line'); scoreLine.appendChild(make('span','score',Number.isInteger(score)?String(score):score.toFixed(1))); scoreLine.appendChild(make('span','max','/ '+max)); overall.appendChild(scoreLine);
const pill=make('span','pill '+tone,toneLabel); overall.appendChild(pill); summary.appendChild(overall);
const verdict=make('div','verdict'); verdict.appendChild(make('div','verdict-label','Verdict')); verdict.appendChild(make('div','verdict-text',data.verdict?String(data.verdict):'Review complete'));
if(data.summary) verdict.appendChild(make('p','verdict-copy',String(data.summary))); summary.appendChild(verdict); frame.appendChild(summary);
if(!subscores.length&&!pros.length&&!cons.length){
  frame.appendChild(make('div','empty','Add subscores, pros, or cons to complete the scorecard.'));
}else{
  const body=make('div','body'); const metrics=make('div','subscores'); metrics.appendChild(make('h3','section-title','Score breakdown'));
  if(!subscores.length) metrics.appendChild(make('div','metric-note','No subscores provided.'));
  subscores.forEach((item)=>{
    const itemMax=item&&Number(item.max)>0?Number(item.max):100; const itemRaw=Number(item&&item.score); const itemScore=Number.isFinite(itemRaw)?Math.max(0,Math.min(itemMax,itemRaw)):0; const pct=itemMax?itemScore/itemMax*100:0;
    const itemTone=pct>=80?'positive':pct>=60?'mixed':'negative'; const metric=make('div','metric');
    const head=make('div','metric-head'); head.appendChild(make('span','metric-name',item&&item.label!=null?String(item.label):'Untitled'));
    head.appendChild(make('span','metric-score',(Number.isInteger(itemScore)?String(itemScore):itemScore.toFixed(1))+' / '+itemMax)); metric.appendChild(head);
    const track=make('div','track'); track.setAttribute('role','progressbar'); track.setAttribute('aria-label',item&&item.label?String(item.label):'Subscore'); track.setAttribute('aria-valuemin','0'); track.setAttribute('aria-valuemax',String(itemMax)); track.setAttribute('aria-valuenow',String(itemScore));
    const fill=make('div','fill '+itemTone); fill.style.width=pct+'%'; track.appendChild(fill); metric.appendChild(track);
    if(item&&item.note) metric.appendChild(make('div','metric-note',String(item.note))); metrics.appendChild(metric);
  });
  body.appendChild(metrics);
  const lists=make('div','lists');
  const addList=(label,items,kind,symbol)=>{
    if(!items.length) return; const section=make('section'); const titleNode=make('h3','list-title '+kind); titleNode.appendChild(make('span','icon',symbol)); titleNode.appendChild(make('span','',label)); section.appendChild(titleNode);
    items.forEach((text)=>{ const point=make('div','point '+kind); point.appendChild(make('span','icon',symbol)); point.appendChild(make('span','',String(text))); section.appendChild(point); }); lists.appendChild(section);
  };
  addList('What works',pros,'pro','✓'); addList('Watch-outs',cons,'con','✗'); body.appendChild(lists); frame.appendChild(body);
}
root.appendChild(frame);
parent.appendChild(host);
